     3→import java.io.*;
     4→import java.util.*;
     5→
     6→/** Exception class for representing parsing errors. */
     7→class ParseException extends RuntimeException {
     8→  ParseException(String s) { super(s); }
     9→}
    10→
    11→/** A parser class for Jam.  Each program requires a separate parser object. */
    12→class Parser {
    13→  
    14→  private Lexer in;
    15→  
    16→  Parser(Lexer i) {
    17→    in = i;
    18→  }
    19→  
    20→  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
    21→  
    22→  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
    23→  
    24→  Lexer lexer() { return in; }
    25→  
    26→  public void initParser() { }
    27→  
    28→  public AST parse() throws ParseException {
    29→    AST prog = parseExp();
    30→    Token t = in.readToken();
    31→    if (t == null) return prog;  // null indicates EOF has been reached
    32→    else throw
    33→      new ParseException("Legal program followed by extra token " + t);
    34→  }
    35→  
    36→  /** Parses:
    37→    *   <exp> :: = if <exp> then <exp> else <exp>
    38→    *            | let <prop-def-list> in <exp>
    39→    *            | map <id-list> to <exp>
    40→    *            | <term> { <biop> <term> }*  // (left associatively!)
    41→    */
    42→  private AST parseExp() {
    43→    Token token = in.readToken();
    44→
    45→    if (token == Lexer.IF) return parseIf();
    46→//    if (token == Lexer.LETREC) return parseLetRec();  // supports addition of letrec
    47→    if (token == Lexer.LET) return parseLet();
    48→    if (token == Lexer.MAP) return parseMap();
    49→    
    50→    /*  Supports the addition of blocks to Jam */
    51→//    if (token == LeftBrace.ONLY) {
    52→//      AST[] exps = parseExps(SemiColon.ONLY,RightBrace.ONLY);  
    53→//      // including closing brace
    54→//      if (exps.length == 0) throw new ParseException("Illegal empty block");
    55→//      return new Block(exps);
    56→//    }
    57→
    58→    /* phrase begin with a term */
    59→    AST exp = parseTerm(token);
    60→    
    61→    Token next = in.peek();
    62→    while (next instanceof OpToken) {
    63→      OpToken op = (OpToken) next;
    64→      in.readToken(); // remove next from input stream
    65→      if (! (op.isBinOp())) error(next, "binary operator");
    66→      AST newTerm = parseTerm(in.readToken());
    67→      exp = new BinOpApp(op.toBinOp(), exp, newTerm);
    68→//      System.err.println("exp updated to: " + exp);
    69→      next = in.peek();
    70→    }
    71→    return exp;
    72→  }
    73→  
    74→  /** Parses:
    75→    *  <term>     ::= { <unop> } <term> | <constant> | <factor> {( <exp-list> )}
    76→    *  <constant> ::= <empty> | <int> | <bool>
    77→    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
    78→    */
    79→  private AST parseTerm(Token token) {
    80→
    81→    if (token instanceof OpToken) {
    82→      OpToken op = (OpToken) token;
    83→      if (! op.isUnOp()) error(op,"unary operator");
    84→      return new UnOpApp(op.toUnOp(), parseTerm(in.readToken()));
    85→    }
    86→    
    87→    if (token instanceof Constant) return (Constant) token;
    88→    AST factor = parseFactor(token);
    89→    Token next = in.peek();
    90→    if (next == LeftParen.ONLY) {
    91→      in.readToken();  // remove next from input stream
    92→      AST[] exps = parseArgs();  // including closing paren
    93→      return new App(factor,exps);
    94→    }
    95→    return factor;
    96→  }
    97→  
    98→  /** Parses:
    99→    *  <factor>   ::= <prim> | <variable> | ( <exp> )
   100→    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
   101→    */
   102→  private AST parseFactor(Token token) {
   103→    
   104→//    System.err.println("parseFactor(" + token + ") called");
   105→    
   106→    if (token == LeftParen.ONLY) {
   107→      AST exp = parseExp();
   108→      token = in.readToken();
   109→      if (token != RightParen.ONLY) error(token,"`)'");
   110→      return exp;
   111→    }
   112→    
   113→    if (! (token instanceof PrimFun) && ! (token instanceof Variable))
   114→      error(token,"constant, primitive, variable, or `('");
   115→    
   116→    // Term\Constant = Variable or PrimFun       
   117→    return (Term) token;
   118→  }      
   119→  
   120→  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
   121→  private AST parseIf() {
   122→    
   123→    AST test = parseExp();
   124→    Token key1 = in.readToken();
   125→    if (key1 != Lexer.THEN) error(key1,"`then'");
   126→    AST conseq = parseExp();
   127→    Token key2 = in.readToken();
   128→    if (key2 != Lexer.ELSE) error(key2,"`else'");
   129→    AST alt = parseExp();
   130→    return new If(test,conseq,alt);
   131→  }
   132→  
   133→    
   134→  /** Parses `let <prop-def-list> in <exp>' given that `let' has already been read. */ 
   135→  private AST parseLet() {
   136→    Def[] defs = parseDefs(false); 
   137→    // consumes `in'; false means rhs may be non Map
   138→    AST body = parseExp();
   139→    return new Let(defs,body);
   140→  }
