   150→//  }
   151→  
   152→  /* Parses `map <id-list> to <exp>' given that `map' has already been read. */
   153→  private AST parseMap() {
   154→
   155→    Variable[] vars = parseVars(); // consumes the delimiter `to'
   156→    AST body = parseExp();
   157→    return new Map(vars, body);
   158→  }
   159→  
   160→  /** Parses `<exp-list> <delim>' where
   161→    *  <exp-list>      ::= <empty> | <prop-exp-list>
   162→    *  <empty> ::=
   163→    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list> 
   164→    */
   165→  private AST[] parseExps(Token separator, Token delim) {
   166→    
   167→    LinkedList<AST> exps = new LinkedList<AST>();
   168→    Token next = in.peek();
   169→    
   170→    if (next == delim) {
